function hashToPositiveInt(value: string) {
  let hash = 5381;
  for (let i = 0; i < value.length; i++) {
    hash = ((hash << 5) + hash) ^ value.charCodeAt(i);
  }
  return Math.abs(hash);
}

export function getAiCoverImageUrl(title: string, seedSource?: string) {
  const seed = hashToPositiveInt(seedSource ?? title);
  const params = new URLSearchParams({ title, seed: String(seed), v: '2' });
  return `/api/ai-image?${params.toString()}`;
}

export function getAllPosts(): BlogPost[] {
  return [...posts].sort((a, b) => (a.date < b.date ? 1 : -1));
}

export function getPostBySlug(slug: string): BlogPost | null {
  return posts.find((p) => p.slug === slug) ?? null;
}
